import{_ as o,c as a,o as i,a1 as s}from"./chunks/framework.DILC4Csi.js";const m=JSON.parse('{"title":"Política de Privacidad: Protección de Datos | OpenCodeDocs","description":"Conoce la política de privacidad y medidas de protección de datos de OpenCodeDocs. Recopilamos, usamos y almacenamos su información personal, y sus derechos sobre los datos.","frontmatter":{"title":"Política de Privacidad: Protección de Datos | OpenCodeDocs","sidebarTitle":"¿Qué sucede con tus datos?","subtitle":"Política de Privacidad: Protección de Datos","description":"Conoce la política de privacidad y medidas de protección de datos de OpenCodeDocs. Recopilamos, usamos y almacenamos su información personal, y sus derechos sobre los datos."},"headers":[],"relativePath":"es/privacy.md","filePath":"es/privacy.md"}'),r={name:"es/privacy.md"};function n(t,e,c,l,d,u){return i(),a("div",null,[...e[0]||(e[0]=[s('<h1 id="politica-de-privacidad" tabindex="-1">Política de Privacidad <a class="header-anchor" href="#politica-de-privacidad" aria-label="Permalink to &quot;Política de Privacidad&quot;">​</a></h1><p>Última actualización: 2026-01-01</p><p>Gracias por utilizar OpenCodeDocs. Valoramos mucho su privacidad y la protección de su información personal. Esta política de privacidad le ayudará a comprender cómo recopilamos, utilizamos, almacenamos y protegemos su información personal.</p><h2 id="_1-informacion-que-recopilamos" tabindex="-1">1. Información que recopilamos <a class="header-anchor" href="#_1-informacion-que-recopilamos" aria-label="Permalink to &quot;1. Información que recopilamos&quot;">​</a></h2><p>Al utilizar los servicios de OpenCodeDocs, podemos recopilar los siguientes tipos de información:</p><h3 id="informacion-de-la-cuenta" tabindex="-1">Información de la cuenta <a class="header-anchor" href="#informacion-de-la-cuenta" aria-label="Permalink to &quot;Información de la cuenta&quot;">​</a></h3><ul><li><strong>Dirección de correo electrónico</strong>: Se utiliza para el registro de cuenta, verificación de inicio de sesión y notificaciones importantes</li><li><strong>Nombre de usuario</strong>: El nombre para mostrar que elija</li><li><strong>Información de la cuenta de GitHub</strong>: Si elige iniciar sesión con GitHub, obtendremos su información pública</li></ul><h3 id="datos-de-uso" tabindex="-1">Datos de uso <a class="header-anchor" href="#datos-de-uso" aria-label="Permalink to &quot;Datos de uso&quot;">​</a></h3><ul><li><strong>Historial de navegación</strong>: Las páginas de tutoriales que visita y cuándo</li><li><strong>Comportamiento de interacción</strong>: Operaciones como copiar código, navegar entre secciones, etc.</li><li><strong>Historial de búsqueda</strong>: Las palabras clave que busca en el sitio</li></ul><h3 id="informacion-del-dispositivo" tabindex="-1">Información del dispositivo <a class="header-anchor" href="#informacion-del-dispositivo" aria-label="Permalink to &quot;Información del dispositivo&quot;">​</a></h3><ul><li><strong>Tipo de navegador</strong>: Chrome, Firefox, Safari, etc.</li><li><strong>Sistema operativo</strong>: Windows, macOS, Linux, etc.</li><li><strong>Dirección IP</strong>: Se utiliza para protección de seguridad y optimización regional</li></ul><h2 id="_2-como-utilizamos-la-informacion" tabindex="-1">2. Cómo utilizamos la información <a class="header-anchor" href="#_2-como-utilizamos-la-informacion" aria-label="Permalink to &quot;2. Cómo utilizamos la información&quot;">​</a></h2><p>La información que recopilamos se utilizará para los siguientes fines:</p><ul><li><strong>Prestación del servicio</strong>: Garantizar que pueda acceder y utilizar el contenido de los tutoriales normalmente</li><li><strong>Experiencia personalizada</strong>: Recordar su progreso de lectura y preferencias</li><li><strong>Mejora del producto</strong>: Analizar patrones de uso para optimizar el contenido y las funciones</li><li><strong>Seguridad</strong>: Detectar comportamientos anómalos y prevenir el abuso</li><li><strong>Envío de notificaciones</strong>: Enviar recordatorios de actualizaciones de tutoriales y anuncios importantes (se puede optar por no recibirlos)</li></ul><h2 id="_3-comparticion-y-divulgacion-de-informacion" tabindex="-1">3. Compartición y divulgación de información <a class="header-anchor" href="#_3-comparticion-y-divulgacion-de-informacion" aria-label="Permalink to &quot;3. Compartición y divulgación de información&quot;">​</a></h2><p>No venderemos su información personal. Solo es posible compartirla en los siguientes casos:</p><ul><li><strong>Proveedores de servicios de terceros</strong>: Como Vercel (alojamiento), Plausible (análisis), solo pueden acceder a la información necesaria para cumplir con sus responsabilidades</li><li><strong>Requisitos legales</strong>: Divulgación de acuerdo con leyes y regulaciones o requisitos gubernamentales</li><li><strong>Protección de derechos</strong>: Situaciones necesarias para proteger los derechos e intereses de OpenCodeDocs y los usuarios</li></ul><h2 id="_4-almacenamiento-y-seguridad-de-datos" tabindex="-1">4. Almacenamiento y seguridad de datos <a class="header-anchor" href="#_4-almacenamiento-y-seguridad-de-datos" aria-label="Permalink to &quot;4. Almacenamiento y seguridad de datos&quot;">​</a></h2><ul><li><strong>Ubicación de almacenamiento</strong>: Los datos se almacenan en servidores seguros ubicados en Estados Unidos y la región de Asia-Pacífico</li><li><strong>Medidas de encriptación</strong>: Los datos transmitidos utilizan encriptación TLS/SSL; los datos sensibles se almacenan con encriptación AES-256</li><li><strong>Control de acceso</strong>: Restricción estricta de los permisos de acceso del personal interno a los datos</li><li><strong>Período de retención</strong>: Después de cancelar la cuenta, los datos personales se eliminarán dentro de los 30 días</li></ul><h2 id="_5-sus-derechos" tabindex="-1">5. Sus derechos <a class="header-anchor" href="#_5-sus-derechos" aria-label="Permalink to &quot;5. Sus derechos&quot;">​</a></h2><p>De acuerdo con la &quot;Ley de Protección de Información Personal&quot; y el GDPR, usted tiene los siguientes derechos:</p><ul><li><strong>Derecho de acceso</strong>: Tiene derecho a ver la información personal que tenemos sobre usted</li><li><strong>Derecho de corrección</strong>: Tiene derecho a solicitar la corrección de información personal inexacta</li><li><strong>Derecho de eliminación</strong>: Tiene derecho a solicitar la eliminación de su información personal</li><li><strong>Derecho de exportación</strong>: Tiene derecho a exportar sus datos en un formato universal</li><li><strong>Derecho de retirar el consentimiento</strong>: Tiene derecho a retirar el consentimiento otorgado anteriormente en cualquier momento</li></ul><p>Si desea ejercer los derechos mencionados anteriormente, póngase en contacto con nosotros a través de la información de contacto a continuación.</p><h2 id="_6-politica-de-cookies" tabindex="-1">6. Política de Cookies <a class="header-anchor" href="#_6-politica-de-cookies" aria-label="Permalink to &quot;6. Política de Cookies&quot;">​</a></h2><p>Utilizamos los siguientes tipos de cookies:</p><ul><li><strong>Cookies necesarias</strong>: Mantener el estado de inicio de sesión, recordar las preferencias de idioma</li><li><strong>Cookies analíticas</strong>: Estadísticas de visitas y patrones de uso (usando Plausible, respetuoso con la privacidad)</li><li><strong>Cookies de publicidad</strong>: <ul><li>Los proveedores de terceros (incluyendo Google) utilizan cookies para mostrar anuncios basados en el historial de visitas previas de los usuarios en su sitio y otros sitios.</li><li>Google utiliza cookies de anuncios para permitir a Google y sus socios mostrar anuncios a los usuarios basados en el historial de visitas de los usuarios a su sitio y/o otros sitios de Internet.</li><li>Los usuarios pueden visitar la <a href="https://www.google.com/settings/ads" target="_blank" rel="noreferrer">Configuración de anuncios de Google</a> para desactivar los anuncios personalizados. Alternativamente, puede guiar a los usuarios para visitar <a href="http://www.aboutads.info/choices/" target="_blank" rel="noreferrer">www.aboutads.info</a> para desactivar las cookies de los proveedores de terceros utilizadas para anuncios personalizados.</li></ul></li></ul><p>Puede administrar las cookies a través de la configuración de su navegador. Deshabilitar las cookies necesarias puede afectar el funcionamiento normal de algunas funciones.</p><h2 id="_7-contactenos" tabindex="-1">7. Contáctenos <a class="header-anchor" href="#_7-contactenos" aria-label="Permalink to &quot;7. Contáctenos&quot;">​</a></h2><p>Si tiene alguna pregunta sobre esta política de privacidad, o necesita ejercer sus derechos sobre los datos, contáctenos a:</p><ul><li><strong>Correo electrónico</strong>: <a href="mailto:vbgatecom@gmail.com" target="_blank" rel="noreferrer">vbgatecom@gmail.com</a></li><li><strong>Tiempo de respuesta</strong>: Responderemos a su solicitud dentro de los 15 días laborables</li></ul>',30)])])}const g=o(r,[["render",n]]);export{m as __pageData,g as default};
